import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// Henüz oluşturmadığımız sayfalar için geçici bileşenler (Mokap)
const AuthPage = () => {
  const [isLogin, setIsLogin] = React.useState(true);

  return (
    <div className="min-h-screen bg-[#FEFAE0] flex items-center justify-center p-6 font-sans"> {/* Butter Yellow Arka Plan */}

      {/* Kart Konteynırı */}
      <div className="bg-white w-full max-w-md p-10 rounded-[2.5rem] shadow-xl shadow-[#F8AD9D]/10 border border-[#FAEDCD]">

        {/* Başlık ve Logo */}
        <div className="text-center mb-10">
          <h1 className="text-4xl font-bold text-[#F8AD9D] tracking-tight mb-2">Planly 🌸</h1>
          <p className="text-gray-400 text-sm">{isLogin ? 'Tekrar hoş geldin!' : 'Aramıza katıl ve planlamaya başla.'}</p>
        </div>

        {/* Form Alanı */}
        <form className="space-y-4" onSubmit={(e) => e.preventDefault()}>
          {!isLogin && (
            <input 
              type="text" 
              placeholder="Ad Soyad" 
              className="w-full p-4 rounded-2xl bg-[#FEFAE0]/30 border border-[#FAEDCD] focus:outline-none focus:ring-2 focus:ring-[#F8AD9D] transition-all placeholder:text-gray-300"
            />
          )}
          <input 
            type="email" 
            placeholder="E-posta Adresi" 
            className="w-full p-4 rounded-2xl bg-[#FEFAE0]/30 border border-[#FAEDCD] focus:outline-none focus:ring-2 focus:ring-[#F8AD9D] transition-all placeholder:text-gray-300"
          />
          <input 
            type="password" 
            placeholder="Şifre" 
            className="w-full p-4 rounded-2xl bg-[#FEFAE0]/30 border border-[#FAEDCD] focus:outline-none focus:ring-2 focus:ring-[#F8AD9D] transition-all placeholder:text-gray-300"
          />

          <button 
            className="w-full bg-[#F8AD9D] text-white font-bold py-4 rounded-2xl shadow-lg shadow-[#F8AD9D]/20 hover:bg-[#f4978e] hover:scale-[1.01] active:scale-95 transition-all duration-200 mt-4"
            onClick={() => window.location.href = '/onboarding'}
          >
            {isLogin ? 'Giriş Yap' : 'Kayıt Ol'}
          </button>
        </form>

        {/* Seçenek Değiştirme */}
        <div className="mt-8 text-center">
          <p className="text-sm text-gray-400">
            {isLogin ? 'Henüz hesabın yok mu?' : 'Zaten üye misin?'}
            <button 
              onClick={() => setIsLogin(!isLogin)}
              className="ml-2 text-[#F8AD9D] font-bold hover:underline"
            >
              {isLogin ? 'Üye Ol' : 'Giriş Yap'}
            </button>
          </p>
        </div>

      </div>
    </div>
  );
};

const OnboardingPage = () => <div className="p-10 bg-white min-h-screen">
  <h2 className="text-3xl font-bold mb-4">Sınav ve Konu Seçimi (Görsel Adım 2)</h2>
  <div className="flex gap-4 mb-4">
    <div className="border p-4 w-32 text-center rounded">YKS</div>
    <div className="border p-4 w-32 text-center rounded">KPSS</div>
  </div>
  <a href="/dashboard" className="text-blue-500 underline">Seçimleri Kaydet ve Devam Et</a>
</div>;

const DashboardPage = () => <div className="p-10 bg-[#FEFAE0] min-h-screen flex gap-6">
  {/* Ana Takvim Alanı (Görsel Adım 4) */}
  <div className="flex-1 bg-white p-6 rounded-3xl shadow">
    <h3 className="text-xl font-bold mb-4">Haftalık Çalışma Takvimi</h3>
    <div className="grid grid-cols-7 gap-1 h-96 border"> <p>Takvim Buraya</p></div>
  </div>

  {/* Study With Friends Alanı (Söz verdiğimiz kısım) */}
  <div className="w-64 bg-white p-6 rounded-3xl shadow border-l-8 border-[#B5E48C]">
    <h4 className="font-bold text-[#F8AD9D] mb-4">Study with Friends 👥</h4>
    <div className="space-y-2">
      <p className="text-sm">Hedefine 3 arkadaşınla çalış!</p>
      <button className="w-full bg-[#B5E48C] text-white p-2 rounded">Grup Oluştur</button>
    </div>
  </div>
</div>;

function App() {
  return (
    <Router>
      <Routes>
        {/* Varsayılan rota (Giriş Sayfası) */}
        <Route path="/" element={<AuthPage />} />

        {/* Onboarding Adımları */}
        <Route path="/onboarding" element={<OnboardingPage />} />

        {/* Ana Uygulama Paneli */}
        <Route path="/dashboard" element={<DashboardPage />} />

        {/* Bilinmeyen rotaları Giriş sayfasına yönlendir */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
}

export default App;
